type ActivityCategory = 'DEVELOPMENT' | 'INVESTORS' | 'BUYERS' | 'LEADS_CRM' | 'PROPERTIES_DEALS' | 'MARKETING' | 'FINANCIAL' | 'AUTONOMOUS_SYSTEM';

