  marketing: 'Marketing',
  documentation: 'Documentation',
  ceo: 'Executive',
  cto: 'Executive',
  deployment: 'DevOps',
  qa: 'Quality',
  security: 'Security',
  growth: 'Growth',
  investor: 'Investor Relations',
  buyer: 'Business Development',
  deal: 'Real Estate',
  research: 'Research',
  operations: 'Operations',
